  "title": "History of Khayan Township in Myanmar",
  "description": "This course provides a comprehensive exploration of the historical significance and cultural heritage of Khayan Township, Myanmar. Designed for learners with no prior knowledge, it aims to foster an appreciation for the rich history and cultural narratives of the region.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Khayan Township",
      "description": "An overview of Khayan Township, including its geographical location, demographics, and significance within the broader context of Myanmar's history."
    },
    {
      "id": "module2",
      "title": "Historical Timeline of Khayan Township",
      "description": "A detailed examination of key historical events that have shaped Khayan Township from ancient times to the present, highlighting major milestones and transformations."
    },
    {
      "id": "module3",
      "title": "Cultural Heritage of Khayan Township",
      "description": "An exploration of the cultural traditions, practices, and heritage of the people of Khayan Township, focusing on festivals, art, and community life."
    },
    {
      "id": "module4",
      "title": "Contemporary Issues and Future Directions",
      "description": "A discussion on the current socio-economic challenges faced by Khayan Township and the prospects for preserving its cultural heritage in the modern world."
    }
  ]
}
